import java.util.Arrays;
import java.util.Comparator;

public class Solution {
    private static final long MOD = 1_000_000_007;

    /**
     * The problem asks to arrange binary segments (each composed of nums1[i] ones followed by nums0[i] zeros)
     * to form the largest possible integer.
     * 
     * The value of a binary string is maximized when the most significant bits are 1s.
     * This suggests a greedy approach based on comparing the relative "value" of two segments.
     * 
     * Let segment A be S_A (n1_A ones followed by n0_A zeros) and segment B be S_B (n1_B ones followed by n0_B zeros).
     * We prefer A before B if S_A + S_B > S_B + S_A (in terms of numerical value).
     * 
     * Consider the two possible concatenations:
     * 1. A followed by B: S_A S_B
     * 2. B followed by A: S_B S_A
     * 
     * If S_A S_B > S_B S_A, then A should come before B.
     * 
     * Let L_A = n1_A + n0_A and L_B = n1_B + n0_B be the lengths.
     * 
     * S_A S_B represents a number where the value is:
     * Value(S_A) * 2^(L_B) + Value(S_B)
     * 
     * The comparison is complex because we are dealing with segments, not just numbers.
     * The standard approach for arranging strings to form the lexicographically largest string 
     * (which corresponds to the largest number for fixed length) is to define a custom comparator:
     * String a comes before String b if (a + b) > (b + a) lexicographically.
     * 
     * In our case, the segments are not simple strings of '0' and '1' but are defined by counts.
     * The segment S_i is $1^{n1_i} 0^{n0_i}$.
     * 
     * We need to compare $S_A S_B$ vs $S_B S_A$.
     * $S_A S_B = (1^{n1_A} 0^{n0_A}) (1^{n1_B} 0^{n0_B})$
     * $S_B S_A = (1^{n1_B} 0^{n0_B}) (1^{n1_A} 0^{n0_A})$
     * 
     * Since the segments are constructed by concatenating blocks of 1s followed by blocks of 0s,
     * the comparison is equivalent to comparing the strings lexicographically.
     * 
     * We must first create the actual segments (as strings or comparable representations) and then sort them.
     */
    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;
        String[] segments = new String[n];

        for (int i = 0; i < n; i++) {
            long n1 = nums1[i];
            long n0 = nums0[i];

            // Construct the segment: n1 ones followed by n0 zeros
            StringBuilder sb = new StringBuilder();
            for (int j = 0; j < n1; j++) {
                sb.append('1');
            }
            for (int j = 0; j < n0; j++) {
                sb.append('0');
            }
            segments[i] = sb.toString();
        }

        // Sort the segments using the custom comparator: a comes before b if (a + b) > (b + a)
        Arrays.sort(segments, new Comparator<String>() {
            @Override
            public int compare(String a, String b) {
                String ab = a + b;
                String ba = b + a;
                // For descending order (largest number first), we want compare(a, b) < 0 if a should come before b
                // If ab > ba, a should come before b, so we return -1.
                return ba.compareTo(ab); 
                // ba.compareTo(ab) returns:
                // < 0 if ba < ab (i.e., ab > ba) -> return negative -> a comes before b (correct for largest)
                // > 0 if ba > ab (i.e., ab < ba) -> return positive -> b comes before a (correct for largest)
            }
        });

        // Concatenate the sorted segments
        StringBuilder resultSb = new StringBuilder();
        for (String segment : segments) {
            resultSb.append(segment);
        }

        String finalBinaryString = resultSb.toString();
        int L = finalBinaryString.length();

        // Calculate the decimal value modulo 10^9 + 7
        long result = 0;
        for (int i = 0; i < L; i++) {
            char c = finalBinaryString.charAt(L - 1 - i); // Process from LSB to MSB for easier math
            long powerOf2 = 1;

            // Calculate 2^i mod MOD
            for (int j = 0; j < i; j++) {
                powerOf2 = (powerOf2 * 2) % MOD;
            }

            if (c == '1') {
                result = (result + powerOf2) % MOD;
            }
        }

        // A more standard way using Horner's method (left to right):
        long finalResult = 0;
        for (int i = 0; i < L; i++) {
            int bit = finalBinaryString.charAt(i) - '0';
            // finalResult = (finalResult * 2 + bit) % MOD
            finalResult = (finalResult * 2) % MOD;
            finalResult = (finalResult + bit) % MOD;
        }

        return finalResult;
    }
}
