                        d2 = '1'; // In s2
                    } else if (idx < s2.ones + s2.zeros) {
                        d2 = '0'; // In s2
                    } else if (idx < s2.ones + s2.zeros + s1.ones) {
                        d2 = '1'; // In s1
                    } else {
                        d2 = '0'; // In s1
                    }

                    if (d1 != d2) {
                        // '1' > '0' in lexicographical order
                        return Character.compare(d2, d1); // If d2='1' and d1='0', return positive (d2 > d1) -> s2s1 > s1s2
                                                            // Wait, we want s1s2 > s2s1. So if d1 > d2, return positive.
                        return Character.compare(d1, d2); // Return > 0 if d1 > d2 (s1s2 is larger)
                    }
                    idx++;
                }
                return 0;
