            // and the total length processed so far, 'total_length'.

            // Let's maintain total_length instead of recalculating the shift for every segment.
        }

        // Recalculation using iterative multiplication (standard method for building numbers)
        long current_result = 0;
        long total_length = 0;

        for (SegmentBuilder sb_sorted : sb) {
            long ones = sb_sorted.ones;
            long zeros = sb_sorted.zeros;

            // The current segment S has length L = ones + zeros.
            // The segment value V is: (2^ones - 1) * 2^zeros

            // We are calculating: Result_new = Result_old * 2^L + V

            // 1. Multiply old result by 2^L (shift left)
            long shift_factor = power(2, ones + zeros, M);
            current_result = (current_result * shift_factor) % M;

            // 2. Add the value V of the current segment
            // V = (2^ones - 1) * 2^zeros

            long val_ones = (power(2, ones, M) - 1 + M) % M;
            long shift_zeros = power(2, zeros, M);
            long V = (val_ones * shift_zeros) % M;

            current_result = (current_result + V) % M;
        }

        return current_result;
    }

    private static long power(long base, long exp, long mod) {
        long res = 1;
        base %= mod;
        while (exp > 0) {
            if (exp % 2 == 1) {
                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            exp /= 2;
        }
        return res;
    }
