import java.util.Arrays;
import java.util.Comparator;

public class Solution {
    private static final long MOD = 1_000_000_007L;

    /**
     * Compares two segments based on the value they represent when placed before another segment.
     * Segment A is represented by (nums1A, nums0A) and Segment B by (nums1B, nums0B).
     * We want to place A before B if the resulting number is larger.
     * This is equivalent to comparing A + B vs B + A.
     *
     * A + B: (1...1)(0...0) + (1...1)(0...0)
     * B + A: (1...1)(0...0) + (1...1)(0...0)
     *
     * The comparison logic for greedy sorting of binary strings to maximize value is:
     * String A should come before string B if (A + B) > (B + A) lexicographically.
     *
     * Let's simplify the comparison for the structure: '1...1' followed by '0...0'.
     * Segment i has value roughly 2^(nums1[i] + nums0[i] - 1) * (something based on the first bit being 1 if nums1[i]>0).
     *
     * A segment S_i = '1...1' (nums1[i] times) + '0...0' (nums0[i] times).
     * Its value is sum_{j=0}^{nums1[i]-1} 2^(nums1[i] + nums0[i] - 1 - j).
     *
     * A simpler way to compare two numbers represented by blocks:
     * Compare the value of the combined string S_i + S_j with S_j + S_i.
     *
     * S_i = 1^a 0^b, S_j = 1^c 0^d
     * S_i + S_j = 1^a 0^b 1^c 0^d
     * S_j + S_i = 1^c 0^d 1^a 0^b
     *
     * We want to sort such that if S_i comes before S_j, S_i+S_j > S_j+S_i.
     *
     * This is the standard comparison for maximizing a concatenated string:
     * Compare String(i) + String(j) vs String(j) + String(i).
     */
    static class Segment {
        int nums1;
        int nums0;

        public Segment(int n1, int n0) {
            this.nums1 = n1;
            this.nums0 = n0;
        }

        // Returns the binary string representation of the segment
        public String toBinaryString() {
            StringBuilder sb = new StringBuilder();
            for (int i = 0; i < nums1; i++) {
                sb.append('1');
            }
            for (int i = 0; i < nums0; i++) {
                sb.append('0');
            }
            return sb.toString();
        }
    }

    public static long solve(long[] nums1, long[] nums0) {
        int n = nums1.length;
        Segment[] segments = new Segment[n];
        for (int i = 0; i < n; i++) {
            segments[i] = new Segment((int) nums1[i], (int) nums0[i]);
        }

        // Custom comparator for greedy sorting
        Arrays.sort(segments, new Comparator<Segment>() {
            @Override
            public int compare(Segment s1, Segment s2) {
                // Compare s1 + s2 vs s2 + s1 lexicographically
                String s1_str = s1.toBinaryString();
                String s2_str = s2.toBinaryString();
                String s1s2 = s1_str + s2_str;
                String s2s1 = s2_str + s1_str;

                // We want descending order (largest first), so if s1s2 > s2s1, s1 comes before s2 (return -1)
                return s2s1.compareTo(s1s2); // Compare s2s1 vs s1s2. If s1s2 > s2s1, s1s2 is lexicographically larger, compare returns positive, so s2 comes first (incorrect for descending)
                // If s1s2 > s2s1, we want s1 before s2, so compare should return negative.
                // s1s2.compareTo(s2s1) returns positive if s1s2 > s2s1.
                return s1s2.compareTo(s2s1);
            }
        });

        // Concatenate the segments in sorted order and calculate the value modulo 10^9 + 7
        long result = 0;
        for (Segment segment : segments) {
            String s = segment.toBinaryString();
            for (char c : s.toCharArray()) {
                if (c == '1') {
                    result = (result * 2) % MOD;
                    result = (result + 1) % MOD;
                } else { // c == '0'
                    result = (result * 2) % MOD;
                }
            }
        }

        return result;
    }
